            // Assert
            resultado.Should().NotBeNull();
            // Verifica se o WHERE contém a condição com LIKE
            resultado.Value.where.Should().Contain($"[{DBTerceirosDicInfo.PTabelaNome}].[{DBTerceirosDicInfo.Fone}]");
            resultado.Value.where.Should().Contain("like @terFone");
